import React from 'react';

const JobServices = () => (
    <section className="py-20 px-8 bg-gray-900 text-white">
        <h2 className="text-3xl font-bold text-center mb-10 text-orange-500">Kategori Pekerjaan Unggulan</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 max-w-6xl mx-auto">
            {['Teknologi & IT', 'Marketing & Sales', 'Administrasi'].map((cat, i) => (
                <div key={i} className="p-6 bg-gray-800 rounded-xl border border-gray-700 hover:border-orange-500 transition">
                    <h3 className="text-xl font-semibold mb-2">{cat}</h3>
                    <p className="text-gray-400 text-sm">Temukan ribuan lowongan di bidang {cat.toLowerCase()} khusus untuk Anda.</p>
                </div>
            ))}
        </div>
    </section>
);
export default JobServices;
